import{_ as t,a as r,b as o,c as a,d as n,e as i}from"./chunks/simplerov 5.Dabd9i25.js";import{_ as s,o as d,c as l,ag as u}from"./chunks/framework.DXGyWiRo.js";const v=JSON.parse('{"title":"Building a Vehicle Frame","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/building-a-vehicle-frame.md","filePath":"robotics/building-a-vehicle-frame.md"}'),c={name:"robotics/building-a-vehicle-frame.md"};function h(m,e,f,p,g,b){return d(),l("div",null,[...e[0]||(e[0]=[u('<h1 id="building-a-vehicle-frame" tabindex="-1">Building a Vehicle Frame <a class="header-anchor" href="#building-a-vehicle-frame" aria-label="Permalink to &quot;Building a Vehicle Frame&quot;">​</a></h1><h2 id="frame-selection" tabindex="-1">Frame Selection <a href="#frame-selection" id="frame-selection"></a> <a class="header-anchor" href="#frame-selection" aria-label="Permalink to &quot;Frame Selection &lt;a href=&quot;#frame-selection&quot; id=&quot;frame-selection&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>The first step in building an ArduSub vehicle is to pick a vehicle &quot;frame&quot; from which to mount and orient thrusters. Some frames use less thrusters, while others have better manueverability (strafe, pitch/roll stability).</p><p>ArduSub includes a high-level motor library that can configure motors in any configuration. This library is used to implement a number of supported frame configurations.</p><p>All configurations are shown from <strong>top-down view</strong>. Green thrusters indicate counter-clockwise propellers and blue thrusters indicate clockwise propellers (or vice-versa). The numbers next to each thruster correspond to the numbered main output on the autopilot board when the ESC signal wires are plugged in.</p><p>Currently supported are:</p><table tabindex="0"><thead><tr><th><p><img src="'+t+'" alt=""></p><p><strong>BlueROV1 Configuration</strong> with 6-DOF thruster positioning. (Frame: <code>bluerov</code>)</p></th><th><p><img src="'+r+'" alt=""></p><p><strong>Vectored ROV</strong> with side-by-side vertical thrusters. Used for the <a href="http://bluerov2.com/"><em>BlueROV2</em></a>. (Frame: <code>vectored</code>)</p></th><th><p><img src="'+o+'" alt=""></p><p><strong>Vectored ROV w/ Four Vertical Thrusters</strong>, an 8-thruster configuration with 6-DOF control and heavy-lifting capacity. Used for the <a href="https://bluerobotics.com/introducing-bluerov2-heavy/"><em>BlueROV2 Heavy</em></a>. (Frame: <code>vectored6dof</code>)</p></th></tr></thead><tbody><tr><td><p><img src="'+a+'" alt=""></p><p><strong>ROV</strong> with a single vertical thruster. (Frame: <code>simplerov</code>)</p></td><td><p><img src="'+n+'" alt=""></p><p><strong>ROV</strong> with side-by-side vertical thrusters. (Frame: <code>simplerov</code>)</p></td><td><p><img src="'+i+'" alt=""></p><p><strong>ROV</strong> with a lateral thruster and side-by-side vertical thrusters. (Frame: <code>simplerov</code>)</p></td></tr></tbody></table><h3 id="custom-frame" tabindex="-1">Custom Frame <a href="#custom-frame" id="custom-frame"></a> <a class="header-anchor" href="#custom-frame" aria-label="Permalink to &quot;Custom Frame &lt;a href=&quot;#custom-frame&quot; id=&quot;custom-frame&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>If the vehicle thruster configuration a user wishes to build is not one of the pre-build frames, then a custom frame may be configured in using this documentation: <a href="http://www.ardusub.com/developers/developers.html#making-a-custom-configuration" target="_blank" rel="noreferrer">Making a Custom Configuration</a></p><h3 id="component-selection" tabindex="-1">Component Selection <a href="#component-selection" id="component-selection"></a> <a class="header-anchor" href="#component-selection" aria-label="Permalink to &quot;Component Selection &lt;a href=&quot;#component-selection&quot; id=&quot;component-selection&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>The minumum required electronic components can be found in the Hardware Options: Required Hardware section of this documentation book.</p><p>Vehicle frames are commonly built out of corrosion resitant material such as HDPE and aluminum.</p><h3 id="wiring-and-connections" tabindex="-1">Wiring and Connections <a href="#wiring-and-connections" id="wiring-and-connections"></a> <a class="header-anchor" href="#wiring-and-connections" aria-label="Permalink to &quot;Wiring and Connections &lt;a href=&quot;#wiring-and-connections&quot; id=&quot;wiring-and-connections&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>The exact wiring configuration depends on the vehicle configuration and the hardware used. The following are the standard channel assignments. Please see the &quot;Frame Selection&quot; for standard thruster numbering.</p><p>The MAIN and AUX output numbers reference the Pixhawk 1 PWM outputs.</p><table tabindex="0"><thead><tr><th>PWM Channel</th><th>Connection</th></tr></thead><tbody><tr><td>MAIN OUT Channel 1</td><td>Thruster #1</td></tr><tr><td>MAIN OUT Channel 2</td><td>Thruster #2</td></tr><tr><td>MAIN OUT Channel 3</td><td>Thruster #3</td></tr><tr><td>MAIN OUT Channel 4</td><td>Thruster #4 (if used)</td></tr><tr><td>MAIN OUT Channel 5</td><td>Thruster #5 (if used)</td></tr><tr><td>MAIN OUT Channel 6</td><td>Thruster #6 (if used)</td></tr><tr><td>MAIN OUT Channel 7</td><td>Thruster #7 (if used)</td></tr><tr><td>MAIN OUT Channel 8</td><td>Thruster #8 (if used)</td></tr><tr><td>User Configurable (MAIN or AUX)</td><td>LED Lights</td></tr><tr><td>User Configurable (MAIN or AUX)</td><td>Camera Tilt Servo</td></tr></tbody></table><p>The hardware also has other input/output ports including I2C and serial ports. These are the recommended connections for those ports.</p><table tabindex="0"><thead><tr><th>Port</th><th>Connection</th></tr></thead><tbody><tr><td>I2C</td><td>Pressure sensor (MS58XX)</td></tr><tr><td>USB Serial Port</td><td>Companion computer (if used)</td></tr><tr><td>Power Port</td><td>Power Module</td></tr></tbody></table><h3 id="reference-frames" tabindex="-1">Reference Frames <a href="#reference-frames" id="reference-frames"></a> <a class="header-anchor" href="#reference-frames" aria-label="Permalink to &quot;Reference Frames &lt;a href=&quot;#reference-frames&quot; id=&quot;reference-frames&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>If deciding on which components to use is too daunting for first time builders, Blue Robotics sells the <a href="https://bluerobotics.com/store/rov/bluerov2/" target="_blank" rel="noreferrer">BlueROV2</a> which may be used as a semi-complete &quot;reference frame&quot; from which to understand the ArduSub control system. Components can be reused and reconfigured for custom frame designs.</p><h3 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h3><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',23)])])}const _=s(c,[["render",h]]);export{v as __pageData,_ as default};
